def generate_articles():
    """生成200篇文章并保存为JSON"""
    all_articles = []
    for major, data in ARTICLES.items():
        for art in data["articles"]:
            all_articles.append({
                "title": art["title"],
                "content": art["content"],
                "category": art["category"],
                "tags": data["tags"],
                "major": major,
                "source": "zhihu",
            })

    with open(OUTPUT_JSON, "w", encoding="utf-8") as f:
        json.dump(all_articles, f, ensure_ascii=False, indent=2)

    print(f"✅ 生成 {len(all_articles)} 篇知乎风格考研文章")
    print(f"   保存到: {OUTPUT_JSON}")

    # 统计各专业数量
    from collections import Counter
    major_counts = Counter(a["major"] for a in all_articles)
    cat_counts = Counter(a["category"] for a in all_articles)
    print(f"   专业分布: {dict(major_counts)}")
    print(f"   类别分布: {dict(cat_counts)}")

    return all_articles


def import_to_db(articles=None):
    """导入文章到GradPath数据库"""
    if articles is None:
        with open(OUTPUT_JSON, "r", encoding="utf-8") as f:
            articles = json.load(f)

    # 在Docker环境中使用app.database的engine
    sys.path.insert(0, "/app")
    from sqlalchemy import text
    from app.database import engine

    CATEGORY_MAP = {
        "择校": "择校",
        "备考": "复习",
        "调剂": "调剂",
        "复试": "复试",
    }

    imported = 0
    errors = 0
    with engine.connect() as conn:
        for item in articles:
            try:
                mapped_cat = CATEGORY_MAP.get(item["category"], item["category"])
                conn.execute(
                    text(
                        "INSERT INTO knowledge_articles "
                        "(id, title, content, category, tags, source, metadata, is_published, created_at, updated_at) "
                        "VALUES (gen_random_uuid(), :t, :c, :cat, :tags, :src, :meta, true, NOW(), NOW()) "
                        "ON CONFLICT DO NOTHING"
                    ),
                    {
                        "t": item["title"],
                        "c": item["content"],
                        "cat": mapped_cat,
                        "tags": json.dumps(item.get("tags", []), ensure_ascii=False),
                        "src": item.get("source", "zhihu"),
                        "meta": json.dumps({"major": item.get("major", "")}, ensure_ascii=False),
                    },
                )
                imported += 1
            except Exception as e:
                errors += 1
                if errors <= 5:
                    print(f"Error: {e}")
        conn.commit()

    print(f"✅ 导入完成: {imported} 篇成功, {errors} 篇失败")
    return imported, errors


if __name__ == "__main__":
    if "--import" in sys.argv:
        # Docker内执行导入
        import_to_db()
    elif "--generate" in sys.argv or len(sys.argv) == 1:
        # 生成JSON
        articles = generate_articles()
        print(f"\n📊 统计: 共 {len(articles)} 篇文章")
        print("   下一步: 复制到Docker并执行 --import 导入数据库")
    else:
        print("用法:")
        print("  python zhihu_final.py           # 生成JSON")
        print("  python zhihu_final.py --import  # 导入数据库(Docker内)")
